 *
 * # SSE Format
 *
 * Events are serialized to the following text format:
 * ```text
 * event: event_type
 * data: {"json":"value"}
 * id: event-123
 * retry: 3000
 * ```
 */
data class SseEvent(
    /** Event type (optional) */
